class ETG_SalesAgreementVersionCompareController extends SrsReportRunController
{
    SalesAgreementHeaderHistory                 salesAgreementHeaderHistory;
    PurchAgreementHeaderHistory                 PurchAgreementHeaderHistory;
    ETG_SalesAgreementVersionCompareContract    versonCompareContract;

}

Method.Source:
protected void prePromptModifyContract()//prePromptModifyContract()//preRunModifyContract()
{
    versonCompareContract = this.parmReportContract().parmRdpContract() as ETG_SalesAgreementVersionCompareContract;
    if (this.parmArgs().record() && this.parmArgs().dataset() == tableNum(SalesAgreementHeaderHistory))
    {
        salesAgreementHeaderHistory = this.parmArgs().record();
        versonCompareContract.parmAgreementId(salesAgreementHeaderHistory.SalesNumberSequence);
        versonCompareContract.parmIsSalesAgreement(NoYes::Yes);
    }
    else if(this.parmArgs().record() && this.parmArgs().dataset() == tableNum(PurchAgreementHeaderHistory))
    {
        PurchAgreementHeaderHistory = this.parmArgs().record();
        versonCompareContract.parmAgreementId(PurchAgreementHeaderHistory.PurchNumberSequence);
        versonCompareContract.parmIsSalesAgreement(NoYes::No);
    }
    super();
}

public static void main(Args _args)
{
    ETG_SalesAgreementVersionCompareController controller = new ETG_SalesAgreementVersionCompareController();
    controller.parmReportName(ssrsReportStr(ETG_SalesAgreementCompareReport,Report));//ETG_SalesAgreementHistoryCompare //ETG_SalesAgreementCompareReport
    controller.parmArgs(_args);
    controller.parmShowDialog(true);
    controller.parmLoadFromSysLastValue(false);
    controller.startOperation();

}
